CardDescription.displayName = "CardDescription"

const CardContent = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("p-6 pt-6", className)} {...props} />
  )
)
CardContent.displayName = "CardContent"

const CardFooter = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      className={cn("flex flex-col sm:flex-row sm:items-center sm:justify-end gap-2 p-6 pt-0 border-t-[var(--border-comic)] border-border mt-auto bg-muted/50 rounded-b-[calc(var(--radius-comic)-3px)]", className)}
      {...props}
    />
